const splitRecs=t=>!t?[]:t.split(/\n+/).map(x=>x.trim()).filter(x=>x.length>2);
const recSum=d=>d.recs.reduce((s,r)=>s+(Number(r.total)||0),0);
const okRecs=d=>d.recs.reduce((s,r)=>s+(sc(r.estado_rec)==='ok'?(Number(r.total)||0):0),0);
const noRecs=d=>d.recs.reduce((s,r)=>s+(sc(r.estado_rec)==='no'?(Number(r.total)||0):0),0);
const acogInst=d=>d.recs.filter(r=>sc(r.estado_rec)==='ok').length;
const docState=d=>{const okc=acogInst(d),n=d.recs.length;if(okc===0)return{cls:'no',text:'No acogida'};if(okc===n)return{cls:'ok',text:'Acogida'};return{cls:'mix',text:okc+' de '+n+' acogidas'};};
const RX=/^[\s]*[IVXLC0-9]+[\.\)º°]*\s*/;
function verbOf(t){let s=(t||'').replace(RX,'').trim();let w=(s.split(/\s+/)[0]||'').replace(/[^0-9A-Za-zÀ-ſ]/g,'');return (w||'Ver').toUpperCase();}
function verbBlock(texts,tags){
  const chips=texts.map((t,k)=>`<button class="verb" data-k="${k}">${verbOf(t)}<i>${k+1}</i></button>`).join('');
  const bodies=texts.map((t,k)=>`<div class="acc" data-k="${k}"><div class="acc-in">${tags&&tags[k]?'<span class="btag">'+tags[k]+'</span>':''}<p>${t.replace(RX,'')}</p></div></div>`).join('');
  return `<div class="verbwrap"><div class="verbs">${chips}</div><div class="bodies">${bodies}</div></div>`;
}
function buildDisp(d){
  const out=[],fam={};
  d.recs.forEach(r=>{
    const low=(r.institucion||'').trim().toLowerCase();
    let key=null;
    if(low.startsWith('gobierno regional'))key='reg';
    else if(low.startsWith('ministerio de')||low.startsWith('ministerio del'))key='min';
    if(key){(fam[key]=fam[key]||[]).push(r);}else out.push(r);
  });
  Object.keys(fam).forEach(k=>{
    const arr=fam[k];
    if(arr.length>=3){
      out.push({_group:k,institucion:k==='reg'?'Gobiernos Regionales':'Ministerios',
        estado_rec:arr[0].estado_rec,acciones:arr[0].acciones,_count:arr.length,
        _totalRecs:arr.reduce((s,x)=>s+(Number(x.total)||0),0),
        total:k==='reg'?arr[0].total:undefined,texto:arr[0].texto,
        _items:arr.map(x=>({name:(x.institucion||'').trim(),total:x.total,texto:x.texto,estado_rec:x.estado_rec}))});
    }else{arr.forEach(r=>out.push(r));}
  });
  return out;
}
const dispCount=d=>buildDisp(d).length;

/* ===== count-up ===== */
function countUp(el,to,ms,suf){if(!el)return;let n=0;const step=Math.max(1,Math.ceil(to/(ms/24)));const t=setInterval(()=>{n+=step;if(n>=to){n=to;clearInterval(t)}el.textContent=n+(suf||'');},24);}

/* ===== panorama ===== */
const prowsEl=document.getElementById('prows');
function renderPanorama(list){
  const maxRecs=Math.max(1,...list.map(recSum));
  prowsEl.innerHTML=list.map((d)=>{
    const ok=okRecs(d),no=noRecs(d),v=recSum(d);const i=DOCS.indexOf(d);
    const tip=`<div class="tt">${d.short} · ${d.tipo}</div><div class="tk"><span class="ok">Acogidas</span><b class="ok">${ok}</b></div><div class="tk"><span class="no">No acogidas</span><b class="no">${no}</b></div><div class="tk"><span class="tot">Total</span><b class="tot">${v}</b></div>`;
    return `<div class="prow" data-i="${i}" data-tip="${encodeURIComponent(tip)}"><span class="pl">${d.short}</span><div class="ptrack">
      <span class="seg ok" data-w="${ok/maxRecs*100}"></span><span class="seg no" data-w="${no/maxRecs*100}"></span></div><span class="pv">${v}</span></div>`;
  }).join('');
  requestAnimationFrame(()=>prowsEl.querySelectorAll('.seg').forEach(s=>s.style.width=parseFloat(s.dataset.w)+'%'));
}
const tip=document.getElementById('tip');
prowsEl.addEventListener('mousemove',e=>{const row=e.target.closest('.prow');if(!row){tip.classList.remove('on');return;}tip.innerHTML=decodeURIComponent(row.dataset.tip);let x=e.clientX+16,y=e.clientY+16;if(x+280>innerWidth)x=e.clientX-296;tip.style.left=x+'px';tip.style.top=y+'px';tip.classList.add('on');});
prowsEl.addEventListener('mouseleave',()=>tip.classList.remove('on'));
prowsEl.addEventListener('click',e=>{const row=e.target.closest('.prow');if(row)openDetail(+row.dataset.i);});

/* ===== KPIs / donut recompute ===== */
function recompute(list){
  const inst=new Set();list.forEach(d=>d.recs.forEach(r=>inst.add((r.institucion||'').trim())));
  const recs=list.reduce((a,d)=>a+recSum(d),0);
  const ok=list.reduce((a,d)=>a+okRecs(d),0);
  countUp(document.getElementById('ov1'),list.length,700);
  countUp(document.getElementById('ov2'),recs,900);
  countUp(document.getElementById('ov3'),inst.size,800);
  countUp(document.getElementById('ov4'),ok,900);
  const pct=recs?Math.round(ok/recs*100):0;
  document.getElementById('donut').style.setProperty('--p',pct);
  countUp(document.getElementById('dpct'),pct,1000,'%');
  countUp(document.getElementById('dok'),ok,1000);
  countUp(document.getElementById('dno'),recs-ok,1000);
  countUp(document.getElementById('dtot'),recs,1000);
  renderPanorama(list);
}

/* ===== mosaic ===== */
const mosaic=document.getElementById('mosaic');
function glare(el){
  el.addEventListener('mousemove',e=>{const r=el.getBoundingClientRect();const mx=e.clientX-r.left,my=e.clientY-r.top;el.style.setProperty('--mx',mx+'px');el.style.setProperty('--my',my+'px');
    const px=(mx/r.width-.5),py=(my/r.height-.5);if(el.classList.contains('tile'))el.style.transform=`translateY(-8px) rotateX(${-py*5}deg) rotateY(${px*6}deg) translateZ(18px)`;});
  el.addEventListener('mouseleave',()=>{if(el.classList.contains('tile'))el.style.transform='';});
}
DOCS.forEach((d,i)=>{
  const ds=docState(d);const feat=i===0;const wide=(DOCS.length%2===0)&&(i===DOCS.length-1);
  const t=document.createElement('div');
  t.className='tile'+(feat?' feat':'')+(wide?' wide':'')+' rise';t.dataset.i=i;t.style.animationDelay=(.66+i*.08)+'s';
  t.innerHTML=`<div class="accent"></div><div class="ghost">${String(i+1).padStart(2,'0')}</div>
    <div class="tstate ${ds.cls}">${ds.text}</div>
    <div class="tlabel">${d.label}</div>
    <div class="ttitle">${d.titulo.replace(/\n/g,' ')}</div>
    ${feat?`<div class="tdesc">${d.objetivo}</div>`:''}
    <div class="tmeta"><span class="tchip b">${d.anio}</span><span class="tchip">${d.linea}</span><span class="tchip">${dispCount(d)} instituciones · ${recSum(d)} recom.</span></div>
    <span class="tgo">Ver informe &rarr;</span>`;
  t.onclick=()=>openDetail(i);glare(t);mosaic.appendChild(t);
});
document.querySelectorAll('.kcard').forEach(glare);

/* ===== filters ===== */
const years=[...new Set(DOCS.map(d=>d.anio))].sort();
const FILTERS=[{k:'all',label:'Todos'},...years.map(y=>({k:'y'+y,label:'Año '+y})),{k:'acog',label:'Solo acogidas'}];
function matchF(d,k){if(k==='all')return true;if(k==='acog')return acogInst(d)>0;if(k[0]==='y')return String(d.anio)===k.slice(1);return true;}
const filtersEl=document.getElementById('filters');
FILTERS.forEach((f,idx)=>{const b=document.createElement('button');b.className='fbtn'+(idx===0?' active':'');b.textContent=f.label;b.onclick=()=>applyFilter(f.k,b);filtersEl.appendChild(b);});
let VIS=DOCS.slice();
function applyFilter(k,btn){
  filtersEl.querySelectorAll('.fbtn').forEach(x=>x.classList.remove('active'));btn.classList.add('active');
  const vis=[];
  document.querySelectorAll('.tile').forEach(t=>{
    const d=DOCS[+t.dataset.i];const ok=matchF(d,k);
    if(ok){vis.push(d);t.classList.remove('hidden');requestAnimationFrame(()=>t.classList.remove('hiding'));}
    else{t.classList.add('hiding');setTimeout(()=>t.classList.add('hidden'),380);}
  });
  VIS=vis.length?vis:DOCS;recompute(VIS);
}

/* ===== offcanvas detail ===== */
const scrim=document.getElementById('scrim'),off=document.getElementById('off'),offInner=document.getElementById('offInner');
let cur=-1;
function detailHTML(i){
  const d=DOCS[i];const disp=buildDisp(d);
  const mx=Math.max(1,...disp.filter(r=>r._group!=='min').map(r=>Number(r.total)||0));
  const recsHtml=disp.map(r=>{
    const cls=sc(r.estado_rec);
    const act=r.acciones?`<div class="act"><div class="k">Acciones futuras</div><div class="v">${r.acciones}</div></div>`:'';
    if(r._group==='reg'){
      const texts=splitRecs(r.texto);
      const names=r._items.map(x=>`<span>${x.name}</span>`).join('');
      const q=Math.round((Number(r.total)||0)/mx*100);
      return `<div class="rec ${cls} reveal"><div class="head"><div class="ring" style="--q:${q}"><b>${r.total||'–'}</b></div>
        <div class="inst"><div class="who">Gobiernos Regionales <span class="regc">(${r._count})</span></div><div class="meta">Las mismas ${r.total} recomendaciones aplicadas a los ${r._count} gobiernos regionales</div></div>
        <div class="pill ${cls}">${r.estado_rec||'—'}</div></div>${verbBlock(texts)}
        <details class="reglist"><summary>Ver los ${r._count} gobiernos regionales</summary><div class="regchips">${names}</div></details>${act}</div>`;
    }
    if(r._group==='min'){
      const texts=[],tags=[];
      r._items.forEach(m=>splitRecs(m.texto).forEach(tx=>{texts.push(tx);tags.push(m.name);}));
      const names=r._items.map(x=>`<span>${x.name} <em>(${x.total})</em></span>`).join('');
      return `<div class="rec ${cls} reveal"><div class="head"><div class="ring" style="--q:100"><b>${r._count}</b></div>
        <div class="inst"><div class="who">Ministerios <span class="regc">(${r._count})</span></div><div class="meta">${r._totalRecs} recomendaciones · notificados a ${r._count} ministerios · pulsa un verbo</div></div>
        <div class="pill ${cls}">${r.estado_rec||'—'}</div></div>${verbBlock(texts,tags)}
        <details class="reglist"><summary>Ver los ${r._count} ministerios notificados</summary><div class="regchips">${names}</div></details>${act}</div>`;
    }
    const texts=splitRecs(r.texto);const q=Math.round((Number(r.total)||0)/mx*100);
    return `<div class="rec ${cls} reveal"><div class="head"><div class="ring" style="--q:${q}"><b>${r.total||'–'}</b></div>
      <div class="inst"><div class="who">${r.institucion||'—'}</div><div class="meta">${r.total||0} recomendación(es) dirigidas · pulsa un verbo para ver el detalle</div></div>
      <div class="pill ${cls}">${r.estado_rec||'—'}</div></div>${verbBlock(texts)}${act}</div>`;
  }).join('');
  const ds=docState(d);
  return `<div class="offtop">
      <button class="close" onclick="closeDetail()">✕</button>
      <span class="dcount">Informe ${String(i+1).padStart(2,'0')} / ${String(DOCS.length).padStart(2,'0')}</span>
      <div class="spacer"></div>
      <div class="dnav"><button id="dp">&larr;</button><button id="dn">&rarr;</button></div>
    </div>
    <div class="offbody">
      <section class="hero reveal"><div class="bignum">${String(i+1).padStart(2,'0')}</div>
        <span class="tag">&#9670; ${d.tipo} &middot; ${d.estado}</span>
        <div class="doc-num">${d.label}</div>
        <div class="title">${d.titulo.replace(/\n/g,' ')}</div>
        <div class="chips">
          <span class="chip"><span class="dot" style="background:var(--blue)"></span>Año ${d.anio}</span>
          <span class="chip"><span class="dot" style="background:var(--blue-d)"></span>Publicado ${d.fecha||'—'}</span>
          <span class="chip"><span class="dot" style="background:var(--red)"></span>${d.linea}</span>
          <span class="chip ${ds.cls==='ok'?'st-ok':ds.cls==='no'?'st-no':'st-mix'}"><span class="dot" style="background:${ds.cls==='ok'?'var(--grn)':ds.cls==='no'?'var(--red)':'var(--amb)'}"></span>${ds.text}</span>
        </div></section>
      <div class="kstrip">
        <div class="ks k1"><b>${dispCount(d)}</b><span>Instituciones</span></div>
        <div class="ks k2"><b>${recSum(d)}</b><span>Recomendaciones</span></div>
        <div class="ks k3"><b>${acogInst(d)}</b><span>Entidades con acogida</span></div>
        <div class="ks k4"><b>${d.anio}</b><span>Año de publicación</span></div>
      </div>
      <div class="panel reveal" style="border:1px solid var(--gbrd);border-radius:18px;padding:22px 24px;background:var(--glass);box-shadow:var(--sh)"><div style="font-size:11px;letter-spacing:1.6px;text-transform:uppercase;color:var(--mut);margin-bottom:12px;font-weight:700">◉ Objetivo del documento</div><p style="font-size:14px;line-height:1.65;color:#2a3340">${d.objetivo}</p></div>
      <div class="panel reveal" style="border:1px solid var(--gbrd);border-radius:18px;padding:22px 24px;background:var(--glass);box-shadow:var(--sh);margin-top:14px"><div style="font-size:11px;letter-spacing:1.6px;text-transform:uppercase;color:var(--mut);margin-bottom:12px;font-weight:700;color:var(--red)">❖ Público beneficiario</div><p style="font-size:14px;line-height:1.65;color:#2a3340">${d.publico}</p></div>
      <div class="sec-h"><h3>Recomendaciones por institución</h3><div class="line"></div><div class="cnt">${dispCount(d)} entidad(es)</div></div>
      <div class="recs">${recsHtml}</div>
    </div>`;
}
function openDetail(i){
  cur=i;offInner.innerHTML=detailHTML(i);
  scrim.classList.add('open');off.classList.add('open');off.scrollTop=0;document.body.style.overflow='hidden';
  const dp=document.getElementById('dp'),dn=document.getElementById('dn');
  dp.disabled=i===0;dn.disabled=i===DOCS.length-1;
  dp.onclick=()=>openDetail(i-1);dn.onclick=()=>openDetail(i+1);
  const io=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target)}}),{root:off,threshold:.06});
  off.querySelectorAll('.reveal').forEach(el=>io.observe(el));
  requestAnimationFrame(()=>off.querySelectorAll('.reveal').forEach(el=>{if(el.getBoundingClientRect().top<innerHeight)el.classList.add('in')}));
}
function closeDetail(){scrim.classList.remove('open');off.classList.remove('open');document.body.style.overflow='';cur=-1;}
/* accordion verbs */
off.addEventListener('click',e=>{
  const b=e.target.closest('.verb');if(!b)return;
  const wrap=b.closest('.verbwrap');const k=b.dataset.k;
  const acc=wrap.querySelector('.acc[data-k="'+k+'"]');const isOpen=acc.classList.contains('open');
  wrap.querySelectorAll('.acc').forEach(a=>a.classList.remove('open'));
  wrap.querySelectorAll('.verb').forEach(v=>v.classList.remove('active'));
  if(!isOpen){acc.classList.add('open');b.classList.add('active');}
});
off.addEventListener('scroll',()=>{const p=off.scrollTop/(off.scrollHeight-off.clientHeight||1);document.getElementById('prog').style.width=(p*100)+'%';});
document.addEventListener('keydown',e=>{
  if(!off.classList.contains('open'))return;
  if(e.key==='Escape')closeDetail();
  if(e.key==='ArrowRight'&&cur<DOCS.length-1)openDetail(cur+1);
  if(e.key==='ArrowLeft'&&cur>0)openDetail(cur-1);
});

